1	const PROCESSING_FEE = 5;
2	
3	type Item = { type: string };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type Step = QuoteStep;
6	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	};
11	
12	export const runScenario = (scenario: Scenario): unknown => {
13	  const results = scenario.steps.map((step) => {
14	    const policyBase = step.items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
15	    const firstInsurance = policyBase * 0.1;
16	    return { premium: policyBase + firstInsurance + PROCESSING_FEE };
17	  });
18	  return { results };
19	};
20

